auto_calc = env['ir.config_parameter'].sudo().get_param('ecosphere_esg.esg_auto_emission_calc')
if auto_calc:
    for record in records:
        for line in record.order_line:
            # We look for a matching factor based on product category for demo simplicity, 
            # or you can use esg.product.profile.
            # In a real system, you'd have a mapping. Here we use a fallback to 'Paper Purchases' for demo,
            # or try to match exactly.
            ef = env['esg.emission.factor'].search([('category', '=', 'purchase')], limit=1)
            if ef:
                env['esg.carbon.transaction'].create({
                    'department_id': record.user_id.employee_id.department_id.id if record.user_id.employee_id else False,
                    'source_module': 'purchase',
                    'source_reference': '%s,%s' % ('purchase.order.line', line.id),
                    'emission_factor_id': ef.id,
                    'quantity': line.product_qty,
                    'state': 'confirmed',
                    'date': record.date_approve or fields.Date.context_today(record),
                })

auto_calc = env['ir.config_parameter'].sudo().get_param('ecosphere_esg.esg_auto_emission_calc')
if auto_calc:
    for record in records:
        # Match travel category
        ef = env['esg.emission.factor'].search([('category', '=', 'travel')], limit=1)
        if ef:
            env['esg.carbon.transaction'].create({
                'department_id': record.employee_id.department_id.id if record.employee_id else False,
                'source_module': 'expense',
                'source_reference': '%s,%s' % ('hr.expense', record.id),
                'emission_factor_id': ef.id,
                'quantity': record.quantity or 1.0,
                'state': 'confirmed',
                'date': record.date or fields.Date.context_today(record),
            })

auto_calc = env['ir.config_parameter'].sudo().get_param('ecosphere_esg.esg_auto_emission_calc')
if auto_calc:
    for record in records:
        ef = env['esg.emission.factor'].search([('category', '=', 'fuel')], limit=1)
        if ef:
            env['esg.carbon.transaction'].create({
                'department_id': record.purchaser_id.employee_id.department_id.id if record.purchaser_id and record.purchaser_id.employee_id else False,
                'source_module': 'fleet',
                'source_reference': '%s,%s' % ('fleet.vehicle.log.fuel', record.id),
                'emission_factor_id': ef.id,
                'quantity': record.liter or 1.0,
                'state': 'confirmed',
                'date': record.date or fields.Date.context_today(record),
            })
